import React, { useEffect, useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import api from '../api';

const ProductDetails = () => {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [error, setError] = useState('');
  const userId = Number(localStorage.getItem('userId'));
  const role = localStorage.getItem('role');
  const navigate = useNavigate();

  useEffect(() => {
    const fetchProduct = async () => {
      try {
        const res = await api.get(`products/${id}`);
        setProduct(res.data);
      } catch (err) {
        setError('Product not found');
      }
    };
    fetchProduct();
  }, [id]);

  const handleDelete = async () => {
    try {
      await api.delete(`/products/${id}`);
      navigate('/');
    } catch (err) {
      setError('Could not delete product');
    }
  };

  const addToWishlist = async () => {
    try {
      await api.post(`/wishlist/${id}`);
      alert('Added to wishlist');
    } catch (err) {
      alert('Failed to add to wishlist');
    }
  };

  if (error) return <p>{error}</p>;
  if (!product) return <p>Loading...</p>;

  const canModify = userId === product.sellerId || role === 'ADMIN';

  return (
    <div>
      <h2>{product.title}</h2>
      {product.imagePath && <img src={`http://localhost:8080${product.imagePath}`} alt={product.title} style={{ maxWidth: 400 }} />}
      <p>{product.description}</p>
      <p>Price: ₹{product.price}</p>
      <p>Category: {product.category}</p>
      <p>Seller: {product.sellerName}</p>
      <button onClick={addToWishlist}>Add to wishlist</button>
      {canModify && (<> <Link to={`/edit/${id}`}><button>Edit</button></Link> <button onClick={handleDelete}>Delete</button></>) }
    </div>
  );
};

export default ProductDetails;
